#include <bits/stdc++.h>
using namespace std;
int n,w,a[1003],dp[10004];
int main(){
	memset(dp,127,sizeof(dp));
    scanf("%d%d",&n,&w);
    for(int i=1;i<=n;i++)
    	scanf("%d",&a[i]);
    dp[0]=0;
    for(int i=1;i<=w;i++)
    	for(int j=1;j<=n;j++)
    		if(i-a[j]>=0)
    			dp[i]=min(dp[i],dp[i-a[j]]+1);
    printf("%d",dp[w]);
    return 0;
}
